{"path": "/tmp/sv-777586973f4246329af54e98932fd6c8/Components/Board/TaskCard.razor", "file_text": "<div class="task-card task-priority-@Task.Priority.ToLowerInvariant()">
    <h4 class="task-title">@Task.Title</h4>
    <p class="task-assignee">@Task.Assignee</p>
    <span class="priority-badge priority-@Task.Priority.ToLowerInvariant()">@Task.Priority</span>
    <span class="task-due-date">@Task.DueDate.ToString("MMM dd")</span>
    <div class="task-actions">
        @if (ShowMoveLeft)
        {
            <button class="btn-move btn-move-left" @onclick="OnMoveLeft">Move Left</button>
        }
        @if (ShowMoveRight)
        {
            <button class="btn-move btn-move-right" @onclick="OnMoveRight">Move Right</button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback OnMoveLeft { get; set; }
    [Parameter] public EventCallback OnMoveRight { get; set; }
}
"}

{"path": "/tmp/sv-777586973f4246329af54e98932fd6c8/Components/Board/AddTaskForm.razor", "file_text": "<div class="add-task-form">
    <div class="form-group">
        <label>Title</label>
        <input type="text" @bind="title" placeholder="Task title" />
    </div>
    <div class="form-group">
        <label>Assignee</label>
        <input type="text" @bind="assignee" placeholder="Assignee name" />
    </div>
    <div class="form-group">
        <label>Priority</label>
        <select @bind="priority">
            <option value="High">High</option>
            <option value="Medium">Medium</option>
            <option value="Low">Low</option>
        </select>
    </div>
    <div class="form-group">
        <label>Due Date</label>
        <input type="date" @bind="dueDate" />
    </div>
    <div class="form-actions">
        <button class="btn-save" @onclick="HandleSave" disabled="@isSaving">
            @(isSaving ? "Saving..." : "Save")
        </button>
        <button class="btn-cancel" @onclick="OnCancel" disabled="@isSaving">Cancel</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnStatus { get; set; } = default!;
    [Parameter] public EventCallback OnCancel { get; set; }
    [Parameter] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnSave { get; set; }

    private string title = string.Empty;
    private string assignee = string.Empty;
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool isSaving;

    private async Task HandleSave()
    {
        if (string.IsNullOrWhiteSpace(title)) return;

        isSaving = true;
        try
        {
            await OnSave.InvokeAsync((title, assignee, priority, dueDate));
        }
        finally
        {
            isSaving = false;
        }
    }
}
"}

{"path": "/tmp/sv-777586973f4246329af54e98932fd6c8/Components/Board/BoardStats.razor", "file_text": "<div class="board-stats">
