    <div class="stat-item">
        <span class="stat-value">@DoneCount</span>
        <span class="stat-label">Done</span>
    </div>
    <div class="stat-item stat-overdue">
        <span class="stat-value">@OverdueCount</span>
        <span class="stat-label">Overdue</span>
    </div>
</div>

@code {
    [Parameter] public int TotalCount { get; set; }
    [Parameter] public int TodoCount { get; set; }
    [Parameter] public int InProgressCount { get; set; }
    [Parameter] public int DoneCount { get; set; }
    [Parameter] public int OverdueCount { get; set; }
}
"}

{"path": "/tmp/sv-777586973f4246329af54e98932fd6c8/Components/Board/BoardSearchBar.razor", "file_text": "<div class="board-search">
    <input type="text"
           placeholder="Search tasks by title..."
           value="@SearchTerm"
           @oninput="HandleInput" />
</div>

@code {
    [Parameter] public string SearchTerm { get; set; } = string.Empty;
    [Parameter] public EventCallback<string> OnSearchChanged { get; set; }

    private async Task HandleInput(ChangeEventArgs e)
    {
        await OnSearchChanged.InvokeAsync(e.Value?.ToString() ?? string.Empty);
    }
}
"}

{"path": "/tmp/sv-777586973f4246329af54e98932fd6c8/Components/Board/KanbanColumn.razor", "file_text": "<div class="kanban-column">
    <div class="column-header">
        <h3>@ColumnName</h3>
        <span class="column-count">@Tasks.Count</span>
    </div>

    <div class="column-body">
        @foreach (var task in Tasks)
        {
            <TaskCard Task="task"
                      ShowMoveLeft="CanMoveLeft"
                      ShowMoveRight="CanMoveRight"
                      OnMoveLeft="() => OnMoveLeft.InvokeAsync(task.Id)"
                      OnMoveRight="() => OnMoveRight.InvokeAsync(task.Id)" />
        }
    </div>

    @if (showForm)
    {
        <AddTaskForm ColumnStatus="@Status"
                     OnSave="HandleSave"
                     OnCancel="() => showForm = false" />
    }
    else
    {
        <button class="btn-add-task" @onclick="() => showForm = true">Add Task</button>
    }
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = default!;
    [Parameter, EditorRequired] public string Status { get; set; } = default!;
    [Parameter] public List<TaskItem> Tasks { get; set; } = [];
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback<int> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<int> OnMoveRight { get; set; }
    [Parameter] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnTaskCreated { get; set; }

    private bool showForm;

    private async Task HandleSave((string Title, string Assignee, string Priority, DateTime DueDate) newTask)
    {
        await OnTaskCreated.InvokeAsync(newTask);
        showForm = false;
    }
}
"}

