@page "/board"
@rendermode InteractiveServer
@using sv_777586973f4246329af54e98932fd6c8.Components.Board
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<div class="board-page">
    @if (isLoading)
    {
        <p class="board-loading">Loading tasks…</p>
    }
    else if (errorMessage is not null)
    {
        <div class="board-error">
            <p>@errorMessage</p>
            <button @onclick="LoadTasks">Retry</button>
        </div>
    }
    else
    {
        <BoardStats TotalCount="allTasks.Count"
                    TodoCount="todoTasks.Count"
                    InProgressCount="inProgressTasks.Count"
                    DoneCount="doneTasks.Count"
                    OverdueCount="overdueTasks.Count" />

        <BoardSearchBar SearchTerm="@searchTerm" OnSearchChanged="HandleSearch" />

        <div class="kanban-board">
            <KanbanColumn ColumnName="To Do" Status="To Do"
                          Tasks="filteredTodo"
                          CanMoveLeft="false" CanMoveRight="true"
                          OnMoveRight="id => MoveTask(id, \"In Progress\")"
                          OnTaskCreated="args => CreateTask(args, \"To Do\")" />

            <KanbanColumn ColumnName="In Progress" Status="In Progress"
                          Tasks="filteredInProgress"
                          CanMoveLeft="true" CanMoveRight="true"
                          OnMoveLeft="id => MoveTask(id, \"To Do\")"
                          OnMoveRight="id => MoveTask(id, \"Done\")"
                          OnTaskCreated="args => CreateTask(args, \"In Progress\")" />

            <KanbanColumn ColumnName="Done" Status="Done"
                          Tasks="filteredDone"
                          CanMoveLeft="true" CanMoveRight="false"
                          OnMoveLeft="id => MoveTask(id, \"In Progress\")"
                          OnTaskCreated="args => CreateTask(args, \"Done\")" />
        </div>
    }
</div>

@code {
    private List<TaskItem> allTasks = [];
    private string searchTerm = string.Empty;
    private bool isLoading = true;
    private string? errorMessage;

    // Unfiltered column lists (for stats)
    private List<TaskItem> todoTasks => allTasks.Where(t => t.Status == "To Do").ToList();
    private List<TaskItem> inProgressTasks => allTasks.Where(t => t.Status == "In Progress").ToList();
    private List<TaskItem> doneTasks => allTasks.Where(t => t.Status == "Done").ToList();
    private List<TaskItem> overdueTasks => allTasks.Where(t => t.DueDate < DateTime.Today).ToList();

    // Search-filtered column lists (for display)
    private List<TaskItem> filteredTodo => ApplySearch(todoTasks);
    private List<TaskItem> filteredInProgress => ApplySearch(inProgressTasks);
    private List<TaskItem> filteredDone => ApplySearch(doneTasks);

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        isLoading = true;
        errorMessage = null;
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private void HandleSearch(string value)
    {
        searchTerm = value;
    }

    private List<TaskItem> ApplySearch(List<TaskItem> tasks)
    {
        if (string.IsNullOrWhiteSpace(searchTerm))
            return tasks;

        return tasks.Where(t => t.Title.Contains(searchTerm, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    private async Task MoveTask(int taskId, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var task = allTasks.First(t => t.Id == taskId);
            allTasks[allTasks.IndexOf(task)] = task with { Status = newStatus };
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task CreateTask((string Title, string Assignee, string Priority, DateTime DueDate) args, string status)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(args.Title, args.Assignee, args.Priority, args.DueDate);
            allTasks.Add(created with { Status = status });
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
    }
}

